import { createElement } from "react";
function ProgressBar({
  className,
  value,
  max = 100,
  height = 8,
  color = "#4CAF50",
  background = "#333",
  borderRadius = 4,
  style
}) {
  const percent = Math.max(0, Math.min(100, value / max * 100));
  return createElement(
    "div",
    {
      className,
      style: {
        display: "flex",
        width: "100%",
        height,
        backgroundColor: background,
        borderRadius,
        overflow: "hidden",
        ...style
      }
    },
    createElement("div", {
      style: {
        width: `${percent}%`,
        height: "100%",
        backgroundColor: color,
        borderRadius
      }
    })
  );
}
export {
  ProgressBar
};
